#include <stdio.h>
int main() {
 int arr[3] = {10, 20, 30};
 int *ptr = arr;
 for(int i=0; i<3; i++) {
 printf("%d ", *(ptr + i));
 }
 return 0;
}

void swap(int *a, int *b) {
 int temp = *a;
 *a = *b;
 *b = temp;
}

int main() {
 int x = 5, y = 10;
 swap(&x, &y);
 return 0;
}
